import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecureFileHandler {

    private static final String BASE_DIRECTORY = "/path/to/directory/";

    public void readFile(String fileName) {
        Path filePath = Paths.get(BASE_DIRECTORY, fileName).normalize().toAbsolutePath();

        if (!filePath.startsWith(Paths.get(BASE_DIRECTORY))) {
            System.out.println("Access to files outside the base directory is not allowed.");
            return;
        }

        try {
            byte[] fileContent = Files.readAllBytes(filePath);
            System.out.println(new String(fileContent));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        SecureFileHandler fileHandler = new SecureFileHandler();
        String userInput = "../../../../../etc/passwd";
        fileHandler.readFile(userInput);
    }
}

